struct Point {
    var x: Double
    var y: Double
    func distance() -> Double {
        return (x*x + y*y).squareRoot()
    }
}

class Vehicle {
    var speed: Int = 0
    func accelerate() { speed += 10 }
}

var p = Point(x: 3, y: 4)
print(p.distance()) // 5.0

let numbers = [3, 1, 4, 1, 5, 9]

// Closure as argument
let sorted = numbers.sorted { $0 < $1 }
print(sorted) // [1, 1, 3, 4, 5, 9]

let doubled = numbers.map { $0 * 2 }
print(doubled)

// Named closure
let greet: (String) -> String = { name in
    return "Hello, \(name)!"
}
print(greet("Bob"))
